import React from "react";
import { useState } from "react";
import "./nav.css";

export default function Nav() {
  const [Active, IsActive] = useState("off");
  const [Style, setStyle] = useState(null);
  const [contianerSocial, setContainerSocial] = useState(null);

  const handleClick = () => {
    if (Active === "off") {
      IsActive("true");
      setStyle("pushMenu");
      setContainerSocial("cointainerSocial");
    } else {
      IsActive("off");
      setStyle(null);
      setContainerSocial(null);
    }
  };

  return (
    <div>
      <div className={Style}>
        <div className={contianerSocial}>
          <div className="social">
            <img className="imgSocial" src="" />
          </div>
          <div className="social">
            <img className="imgSocial" src="" />
          </div>
          <div className="social">
            <img className="imgSocial" src="" />
          </div>
          <div>
            <img className="imgSocial" src="" />
          </div>
        </div>
      </div>

      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

